 362→const isSafeRemoteImageUrl = (imageUrl) => {
 363→    try {
 364→        const parsed = new URL(imageUrl);
 365→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
 366→            return false;
 367→        }
 368→
 369→        const hostname = parsed.hostname.toLowerCase();
 370→        if (!hostname || hostname === 'localhost' || hostname.endsWith('.local') || hostname.endsWith('.internal')) {
 371→            return false;
 372→        }
 373→
 374→        if (net.isIP(hostname) && isPrivateIpAddress(hostname)) {
 375→            return false;
 376→        }
 377→
 378→        return true;
 379→    } catch {
 380→        return false;
 381→    }
 382→};
