1017→const isMetricsAuthorized = (req) => {
1018→    if (!METRICS_TOKEN) {
1019→        return true;
1020→    }
1021→
1022→    const providedToken = String(req.headers['x-metrics-token'] || '').trim();
1023→    return Boolean(providedToken && providedToken === METRICS_TOKEN);
1024→};
