1026→const buildMetricsPayload = () => {
1027→    const routeStats = Array.from(metricsState.routeStats.entries())
1028→        .map(([route, stat]) => ({
1029→            route,
1030→            count: stat.count,
1031→            avgDurationMs: stat.count > 0 ? Number((stat.totalDurationMs / stat.count).toFixed(2)) : 0,
1032→            maxDurationMs: Number(stat.maxDurationMs.toFixed(2)),
1033→            bytesSent: stat.bytesSent,
1034→            statusBuckets: stat.statusBuckets,
1035→        }))
1036→        .sort((a, b) => b.count - a.count);
1037→
1038→    return {
1039→        startedAt: metricsState.startedAt,
1040→        requests: metricsState.requests,
1041→        responses: metricsState.responses,
1042→        inFlight: metricsState.inFlight,
1043→        bytesSent: metricsState.bytesSent,
1044→        statusBuckets: metricsState.statusBuckets,
1045→        routeStats: routeStats,
1046→    };
1047→};
